import re

# Heuristic + semantic rules for prompt injection
INJECTION_PATTERNS = [
    re.compile(r"ignore (all |your )?(previous |prior )?instructions", re.I),
    re.compile(r"you are now (a |an )?(?!assistant)", re.I),
    re.compile(r"pretend (you are|to be)", re.I),
    re.compile(r"system[:\s]*prompt", re.I),
    re.compile(r"DAN mode", re.I),
    re.compile(r"\[INST\]|<<SYS>>|<\|im_start\|>", re.I),  # leaked template tokens
]

def check_injection(text: str) -> dict:
    for pat in INJECTION_PATTERNS:
        m = pat.search(text)
        if m:
            return {"block": True, "pattern": pat.pattern, "match": m.group()}
    return {"block": False}

from presidio_analyzer import AnalyzerEngine
from presidio_anonymizer import AnonymizerEngine

analyzer = AnalyzerEngine()
anonymizer = AnonymizerEngine()

def scan_pii(text: str) -> dict:
    results = analyzer.analyze(
        text=text,
        entities=["PERSON", "EMAIL_ADDRESS", "PHONE_NUMBER",
                  "CREDIT_CARD", "IP_ADDRESS", "LOCATION"],
        language="en",
    )
    if results:
        # Redact and block — never return detected PII
        anonymized = anonymizer.anonymize(text=text, analyzer_results=results)
        return {"block": True, "entities": [r.entity_type for r in results],
                "redacted": anonymized.text}
    return {"block": False}

from fastapi import FastAPI, Request, Response
import json, time

app = FastAPI()

@app.middleware("http")
async def safety_guard_middleware(request: Request, call_next):
    body_bytes = await request.body()
    body = json.loads(body_bytes)
    user_message = next(
        (m["content"] for m in body.get("messages", []) if m["role"] == "user"), ""
    )

    # Input guards
    injection = check_injection(user_message)
    if injection["block"]:
        return _blocked_response("prompt_injection", injection)
    jailbreak = check_jailbreak(user_message)
    if jailbreak["block"]:
        return _blocked_response("jailbreak", jailbreak)
    pii_in = scan_pii(user_message)
    if pii_in["block"]:
        return _blocked_response("pii_in_prompt", pii_in)

    response = await call_next(request)

    # Output guards (stream response must be buffered)
    resp_body = b"".join([chunk async for chunk in response.body_iterator])
    output_text = extract_output_text(resp_body)
    pii_out = scan_pii(output_text)
    if pii_out["block"]:
        return _blocked_response("pii_in_output", pii_out)

    return Response(content=resp_body, status_code=response.status_code,
                    headers=dict(response.headers), media_type=response.media_type)

def _blocked_response(category: str, detail: dict) -> Response:
    payload = json.dumps({
        "error": {"type": "safety_violation", "category": category, "detail": detail},
        "choices": [{"message": {"role": "assistant",
                                 "content": "I cannot respond to that request."},
                      "finish_reason": "content_filter"}]
    })
    return Response(content=payload, status_code=400, media_type="application/json")

import hashlib
from sentence_transformers import SentenceTransformer
import numpy as np

# Exact-match: MD5 fingerprints of known copyrighted passages (64-word chunks)
COPYRIGHTED_FINGERPRINTS: set[str] = set()  # loaded from secure store

# Semantic near-match via embeddings
embed_model = SentenceTransformer("all-MiniLM-L6-v2")
PROTECTED_EMBEDDINGS: np.ndarray = np.array([])  # shape (N, 384)
COSINE_THRESHOLD = 0.92

def chunk_text(text: str, words: int = 64) -> list[str]:
    tokens = text.split()
    return [" ".join(tokens[i:i+words]) for i in range(0, len(tokens), words)]

def check_copyright(output: str) -> dict:
    chunks = chunk_text(output)
    for chunk in chunks:
        # Exact fingerprint
        fp = hashlib.md5(chunk.lower().encode()).hexdigest()
        if fp in COPYRIGHTED_FINGERPRINTS:
            return {"block": True, "method": "fingerprint", "chunk": chunk[:80]}
        # Semantic near-match
        if len(PROTECTED_EMBEDDINGS):
            emb = embed_model.encode([chunk])
            sims = (PROTECTED_EMBEDDINGS @ emb.T).flatten()
            if sims.max() > COSINE_THRESHOLD:
                return {"block": True, "method": "embedding", "similarity": float(sims.max())}
    return {"block": False}
